INSERT INTO `hospitals` VALUES (1,'Ã‡ermik Devlet Hastanesi','Genel Kapasite ve Yeni Hizmet BinasÄ±\r\nYeni Hastane BinasÄ±: Hastane, AÄŸustos 2024\'te 18.810 metrekarelik kapalÄ± alana sahip yeni ve modern binasÄ±na taÅŸÄ±narak 50 yatak kapasitesiyle hizmet vermeye baÅŸlamÄ±ÅŸtÄ±r. Eski binasÄ±ndan taÅŸÄ±ndÄ±ÄŸÄ± iÃ§in gÃ¼ncel adresi deÄŸiÅŸmiÅŸtir.\r\n\r\nKapasite DetaylarÄ±: 25 poliklinik odasÄ±, 3 ameliyathane, 20\'si tek kiÅŸilik ve 15\'i Ã§ift kiÅŸilik olmak Ã¼zere toplam 35 hasta odasÄ± ile hasta kabul etmektedir.\r\n\r\nYoÄŸun BakÄ±m ve Ãœniteler: 4 yataklÄ± yenidoÄŸan yoÄŸun bakÄ±m, 6 yataklÄ± genel yoÄŸun bakÄ±m, 7 cihazlÄ± hemodiyaliz Ã¼nitesi ve 10 hasta kapasiteli fizik tedavi Ã¼nitesi mevcuttur.\r\n\r\n2026 YÄ±lÄ±ndaki Ã–nemli GeliÅŸmeler\r\nAnne Dostu Hastane UnvanÄ± (Ocak 2026): Hastane, SaÄŸlÄ±k BakanlÄ±ÄŸÄ± tarafÄ±ndan yapÄ±lan deÄŸerlendirmeler sonucunda anne ve bebek saÄŸlÄ±ÄŸÄ±nÄ± Ã¶nceleyen standartlarÄ± baÅŸarÄ±yla karÅŸÄ±layarak \"Anne Dostu Hastane\" unvanÄ±nÄ± aldÄ±. Ã‡ermik Devlet Hastanesi, 2026 yÄ±lÄ±nda TÃ¼rkiye genelinde bu unvanÄ± almaya hak kazanan ilk saÄŸlÄ±k tesisi oldu.\r\n\r\nBaÅŸhekim DeÄŸiÅŸikliÄŸi (Åubat 2026): Åubat 2026 baÅŸlarÄ±nda hastane baÅŸhekimliÄŸine Umut KaragÃ¶z\'Ã¼n yerine FÄ±rat TÃ¼rken atanmÄ±ÅŸtÄ±r.\r\n\r\nÃ–ne Ã‡Ä±kan Hizmetler ve DonanÄ±mlar\r\nHastane, yenidoÄŸan sarÄ±lÄ±ÄŸÄ± tedavisini hÄ±zlandÄ±ran tÃ¼nel fototerapi cihazlarÄ± ve mide/baÄŸÄ±rsak hastalÄ±klarÄ±nÄ±n teÅŸhisi iÃ§in kurulan endoskopi/kolonoskopi Ã¼niteleriyle bÃ¶lge halkÄ±na geliÅŸmiÅŸ tÄ±bbi imkanlar sunmaktadÄ±r.\r\n\r\n5 yatak kapasiteli evde saÄŸlÄ±k hizmeti birimi de aktif olarak bÃ¶lge halkÄ±na destek vermektedir.\r\n\r\nGÃ¼ncel Ä°letiÅŸim ve Adres Bilgileri\r\n(Ã–nemli Not: Eski \"Siverek Yolu\" adresi yeni binayla birlikte deÄŸiÅŸmiÅŸtir.)\r\n\r\nAdres: Tepe Mahallesi, DiyarbakÄ±r Caddesi No:128 Ã‡ermik / DiyarbakÄ±r\r\n\r\nTelefon: 0 (412) 606 05 74\r\n\r\nE-posta: dbkrcermikdh.bsh@saglik.gov.tr',38.14381625,39.47553181,'','','2026-